INSERT INTO business_schemes (name, description, min_age, max_age, min_income, max_income, business_type, min_investment, max_investment, states, benefits, eligibility, application_process, deadline, website, funding_amount, ministry, tags) VALUES

('Pradhan Mantri MUDRA Yojana (PMMY)',
 'Provides loans up to ₹10 lakh to non-corporate, non-farm small/micro enterprises. Three categories: Shishu (up to ₹50,000), Kishore (₹50,000 to ₹5 lakh), and Tarun (₹5 lakh to ₹10 lakh).',
 18, 65, 0, 1500000,
 ARRAY['startup','msme','retail','services','manufacturing'], 0, 1000000, ARRAY['all'],
 ARRAY['Collateral-free loans up to ₹10 lakh','Low interest rates','No processing fee','Flexible repayment tenure of 5-7 years','MUDRA Card for working capital needs'],
 ARRAY['Indian citizen aged 18-65','Non-corporate small business entity','Has a business plan or existing business','No previous loan default'],
 ARRAY['Visit nearest bank branch or NBFC','Fill MUDRA loan application form','Submit business plan and identity documents','Bank evaluates and sanctions loan','Loan disbursement within 7-10 working days'],
 'Ongoing', 'https://www.mudra.org.in', 'Up to ₹10 Lakh', 'Ministry of Finance',
 ARRAY['mudra','loan','small business','micro enterprise','collateral free']),

