 ARRAY['Register on Startup India portal','Apply through an eligible incubator','Submit business plan and financials','Expert committee evaluation','Approval and fund disbursement through incubator'],
 'March 2026', 'https://seedfund.startupindia.gov.in', 'Up to ₹50 Lakh', 'DPIIT, Ministry of Commerce',
 ARRAY['startup','seed fund','innovation','technology','incubator']),

